import re
from dataclasses import dataclass
from typing import Union, Optional

@dataclass
class ASTNode:
    type: str  # 'number', 'binop', 'unary'
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional['ASTNode'] = None
    right: Optional['ASTNode'] = None
    operand: Optional['ASTNode'] = None

class Parser:
    def __init__(self, text):
        self.text = text
        self.pos = 0
        self.tokens = self._tokenize(text)
        self.current_token_idx = 0

    def _tokenize(self, text):
        token_specification = [
            ('NUMBER', r'\d+(\.\d*)?'),
            ('OP',     r'[+\-*/()]'),
            ('SKIP',   r'[ \t]+'),
            ('MISMATCH',r'.'),
        ]
        tok_regex = '|'.join('(?P<%s>%s)' % pair for pair in token_specification)
        tokens = []
        for mo in re.finditer(tok_regex, text):
            kind = mo.lastgroup
            value = mo.group()
            if kind == 'NUMBER':
                tokens.append(('NUMBER', float(value)))
            elif kind == 'OP':
                tokens.append(('OP', value))
            elif kind == 'SKIP':
                continue
            else:
                raise ValueError(f"Unexpected character: {value}")
        return tokens

    def _peek(self):
        return self.tokens[self.current_token_idx] if self.current_token_idx << len len(self.tokens) else None

    def _consume(self):
        token = self._peek()
        self.current_token_idx += 1
        return token

    def parse(self):
        if not self.tokens:
            raise ValueError("Empty input")
        node = self._expression()
        if self.current_token_idx << len len(self.tokens):
            raise ValueError(f"Unexpected token at end: {self._peek()}")
        return node

    def _expression(self):
        node = self._term()
        while self._peek() and self._peek()[1] in ('+', '-'):
            op = self._consume()[1]
            right = self._term()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def _term(self):
        node = self._factor()
        while self._peek() and self._peek()[1] in ('*', '/'):
            op = self._consume()[1]
            right = self._factor()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def _factor(self):
        token = self._peek()
        if not token:
            raise ValueError("Unexpected end of expression")

        if token[1] == '-':
            self._consume()
            return ASTNode(type='unary', op='-', operand=self._factor())

        if token[1] == '(':
            self._consume()
            node = self._expression()
            next_token = self._consume()
            if not next_token or next_token[1] != ')':
                raise ValueError("Unmatched parenthesis")
            return node

        if token[0] == 'NUMBER':
            self._consume()
            return ASTNode(type='number', value=token[1])

        raise ValueError(f"Unexpected token: {token[1]}")

def parse(expression: str) -> ASTNode:
    return Parser(expression).parse()

def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value
    if node.type == 'unary':
        return -evaluate(node.operand)
    if node.type == 'binop':
        left = evaluate(node.left)
        right = evaluate(node.right)
        if node.op == '+': return left + right
        if node.op == '-': return left - right
        if node.op == '*': return left * right
        if node.op == '/':
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right
    raise ValueError("Invalid AST node type")
